INSERT INTO `blog_post_images` VALUES (125,1,1,'https://api.ochoworksdesigns.com/files/blog/blog_1757623306.jpg','general',NULL,'Exterior rendering of a modern farmhouse home featuring white siding with dark trim, multiple gable rooflines, large windows, covered porches, and stone foundation accents designed for wide shallow lots',0,'2025-10-23 14:09:18'),(126,1,0,'https://api.ochoworksdesigns.com/files/blog/blog_1757624199.png','general',NULL,'Main floor architectural plan showing open concept layout with kitchen, dining, great room, master suite, office, garage, butler\'s pantry, and covered porches with detailed room dimensions',1,'2025-10-23 14:09:18'),(127,1,0,'https://api.ochoworksdesigns.com/files/blog/blog_1757681356.png','general',NULL,'Second floor plan displaying four bedrooms with private bathrooms and expansive great room providing flexible family living space in this two-story luxury home design',2,'2025-10-23 14:09:18'),(142,3,1,'https://api.ochoworksdesigns.com/files/blog/blog_1772573132.jpg','general',NULL,'Contemporary two-story home exterior featuring clean stucco lines, flat rooflines, arched entry, and spacious 3-car garage with modern architectural details',0,'2026-03-03 21:25:40'),(143,3,0,'https://api.ochoworksdesigns.com/files/blog/blog_1757771451.png','general',NULL,'Main floor plan showing open concept great room and kitchen, primary bedroom suite with ensuite and walk-in closet, home office, powder room, and 3-car garage',1,'2026-03-03 21:25:40'),(144,3,0,'https://api.ochoworksdesigns.com/files/blog/blog_1757771480.png','general',NULL,'Second floor plan featuring large family room, three secondary bedrooms, and two full bathrooms connected by central hallway with staircase',2,'2026-03-03 21:25:40'),(145,11,1,'https://api.ochoworksdesigns.com/files/blog/blog_1772573721.jpg','general',NULL,'Front exterior view of single-story ranch home featuring mixed stone and stucco facades, multiple gable rooflines, large windows, and attached 3-car garage with craftsman-style architectural details',0,'2026-03-03 21:35:25'),(146,11,0,'https://api.ochoworksdesigns.com/files/blog/blog_1759268255.png','general',NULL,'Detailed floor plan of single-story ranch home showing open concept great room and kitchen, primary bedroom suite, three secondary bedrooms, 3.5 bathrooms, office, mudroom, laundry, pantry, covered deck, and 3-car garage layout',1,'2026-03-03 21:35:25'),(150,10,1,'https://api.ochoworksdesigns.com/files/blog/blog_1772573832.jpg','general',NULL,'Exterior view of two-story modern farmhouse with white siding, dark trim, three dormer windows, covered front porch with columns, and attached four-car garage',0,'2026-03-03 21:38:55'),(151,10,0,'https://api.ochoworksdesigns.com/files/blog/blog_1772573832.png','general',NULL,'Main floor plan showing open concept great room and kitchen, master suite with ensuite bath, two secondary bedrooms, office, dining room, and four-car garage',1,'2026-03-03 21:38:55'),(152,10,0,'https://api.ochoworksdesigns.com/files/blog/blog_1772573929.png','general',NULL,'Upper level floor plan featuring three bedrooms, two full bathrooms, and large recreation room for family entertainment and activities',2,'2026-03-03 21:38:55'),(153,6,1,'https://api.ochoworksdesigns.com/files/blog/blog_1761673441.jpg','general',NULL,'Modern farmhouse exterior featuring white siding with dark trim accents, multiple gabled rooflines, covered front porch with columns, and attached 4-car garage',0,'2026-03-03 21:39:40'),(154,6,0,'https://api.ochoworksdesigns.com/files/blog/blog_1761673482.png','general',NULL,'Main floor plan showing open concept kitchen, great room and dining area, master suite, office, guest room, butler pantry, and 4-car garage layout',1,'2026-03-03 21:39:40'),(155,6,0,'https://api.ochoworksdesigns.com/files/blog/blog_1761673441.png','general',NULL,'Upper floor plan displaying four bedrooms, multiple bathrooms, spacious recreation room, and storage areas in well-organized family wing',2,'2026-03-03 21:39:40'),(156,9,1,'https://api.ochoworksdesigns.com/files/blog/blog_1772574020.jpg','general',NULL,'Exterior view of a two-story modern traditional home featuring white stucco siding, dark roofing, exposed beam details, multiple gabled sections, and a three-car garage',0,'2026-03-03 21:40:28'),(157,9,0,'https://api.ochoworksdesigns.com/files/blog/blog_1757972353.png','general',NULL,'Main floor plan featuring open concept great room and kitchen, dining area, master bedroom with office, guest room, three-car garage, laundry room, and patio access',1,'2026-03-03 21:40:28'),(158,9,0,'https://api.ochoworksdesigns.com/files/blog/blog_1757972402.png','general',NULL,'Upper level floor plan showing four bedrooms, shared bathroom, spacious bonus room, loft area, and open area overlooking the main floor below',2,'2026-03-03 21:40:28'),(159,2,1,'https://api.ochoworksdesigns.com/files/blog/blog_1772574158.jpg','general',NULL,'Modern single-story ranch home exterior featuring mixed stone and siding materials, multiple gabled rooflines, large windows, covered entry, and spacious 3-car garage with contemporary architectural details.',0,'2026-03-03 21:42:43'),(160,2,0,'https://api.ochoworksdesigns.com/files/blog/blog_1757769125.png','general',NULL,'Detailed floor plan of single-story ranch home showing open concept great room, kitchen with pantry, dining area, primary suite with en-suite, three additional bedrooms, home office, laundry room, and 3-car garage.',1,'2026-03-03 21:42:43'),(161,7,1,'https://api.ochoworksdesigns.com/files/blog/blog_1757970255.jpg','general',NULL,'Modern single-story ranch home exterior featuring stone and siding materials with covered front entry, large windows, and spacious 3-car garage in a contemporary design',0,'2026-03-03 21:42:57'),(162,7,0,'https://api.ochoworksdesigns.com/files/blog/blog_1757970255.png','general',NULL,'Detailed floor plan showing open concept layout with great room, dining area, kitchen with pantry, master suite with walk-in closet, three additional bedrooms, and 3-car garage',1,'2026-03-03 21:42:57'),(166,13,1,'https://api.ochoworksdesigns.com/files/blog/blog_1772575001.jpg','general',NULL,'Modern Farmhouse single-story exterior featuring board-and-batten siding, natural stone accents, dormer window, covered front entry porch, and a 2-car garage — a charming and timeless curb appeal at dusk.',0,'2026-03-03 21:57:44'),(167,12,1,'https://api.ochoworksdesigns.com/files/blog/blog_1776442434.jpg','general',NULL,'Contemporary two-story home exterior featuring clean modern lines, mixed material facade, 3-car garage with sleek doors, rooftop deck terrace, and large windows showcasing architectural design',0,'2026-04-17 16:13:56'),(168,12,0,'https://api.ochoworksdesigns.com/files/blog/blog_1761942940.png','general',NULL,'Main floor plan showing open concept great room, gourmet kitchen with pantry, primary bedroom suite with ensuite bath, additional bedroom, laundry room, 3-car garage, and RV garage space',1,'2026-04-17 16:13:56'),(169,12,0,'https://api.ochoworksdesigns.com/files/blog/blog_1761942851.png','general',NULL,'Upper floor plan featuring spacious entertainment room, three bedrooms, two bathrooms, office space, and access to rooftop deck with outdoor living area',2,'2026-04-17 16:13:56');
