  `plan_no` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `version` int DEFAULT '1',
  `ordering` int DEFAULT NULL,
  `title` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
