  `specs` json DEFAULT NULL,
  `bedrooms` decimal(4,3) DEFAULT NULL,
  `bathrooms` decimal(4,3) DEFAULT NULL,
  `stories` decimal(4,3) DEFAULT NULL,
  `garage` decimal(4,3) DEFAULT NULL,
  `basement` enum('full','partial','walkout') COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `basement_square_footage` int DEFAULT '0',
  `main_square_footage` int DEFAULT '0',
  `garage_square_footage` int DEFAULT '0',
  `upper_square_footage` int DEFAULT '0',
  `width` decimal(10,4) DEFAULT NULL,
  `depth` decimal(10,4) DEFAULT NULL,
  `price` decimal(10,2) DEFAULT '0.00',
  `status` enum('active','pending','inactive','deleted') COLLATE utf8mb4_unicode_ci DEFAULT 'pending',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `plan_id` (`plan_no`)
) ENGINE=InnoDB AUTO_INCREMENT=1100 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
